import{_ as e,o as t,c as i,ag as s}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Web Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"dashboard/index.md","filePath":"dashboard/index.md"}'),r={name:"dashboard/index.md"};function o(n,a,l,d,h,c){return t(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="web-dashboard" tabindex="-1">Web Dashboard <a class="header-anchor" href="#web-dashboard" aria-label="Permalink to &quot;Web Dashboard&quot;">​</a></h1><p>R3 includes a built-in web dashboard for server management and live monitoring. The frontend is a SvelteKit application embedded into the Rust binary — no separate web server needed.</p><h2 id="enabling-the-dashboard" tabindex="-1">Enabling the Dashboard <a class="header-anchor" href="#enabling-the-dashboard" aria-label="Permalink to &quot;Enabling the Dashboard&quot;">​</a></h2><p>Add a <code>[web]</code> section to your <code>referee.toml</code>:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">web</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enabled = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bind_address = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.0.0.0&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">port = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8080</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># jwt_secret = &quot;your-secret-key&quot;</span></span></code></pre></div><p>The dashboard will be available at <code>http://your-server-ip:8080</code>.</p><h2 id="default-credentials" tabindex="-1">Default Credentials <a class="header-anchor" href="#default-credentials" aria-label="Permalink to &quot;Default Credentials&quot;">​</a></h2><ul><li><strong>Username:</strong> <code>admin</code></li><li><strong>Password:</strong> <code>changeme</code></li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Change the default password immediately after first login via the Admin Users page.</p></div><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><h3 id="live-scoreboard" tabindex="-1">Live Scoreboard <a class="header-anchor" href="#live-scoreboard" aria-label="Permalink to &quot;Live Scoreboard&quot;">​</a></h3><p>Real-time player list with Red/Blue team grouping, scores, and ping. Updates via WebSocket.</p><h3 id="live-chat" tabindex="-1">Live Chat <a class="header-anchor" href="#live-chat" aria-label="Permalink to &quot;Live Chat&quot;">​</a></h3><p>In-game chat messages streamed in real-time with team/all channel badges.</p><h3 id="dashboard-stats" tabindex="-1">Dashboard Stats <a class="header-anchor" href="#dashboard-stats" aria-label="Permalink to &quot;Dashboard Stats&quot;">​</a></h3><p>Six stat cards showing: online players, current map, game type, server uptime, active warnings, and total bans.</p><h3 id="vote-history" tabindex="-1">Vote History <a class="header-anchor" href="#vote-history" aria-label="Permalink to &quot;Vote History&quot;">​</a></h3><p>Track callvotes with player name, vote type, data, and timestamp.</p><h3 id="personal-notes" tabindex="-1">Personal Notes <a class="header-anchor" href="#personal-notes" aria-label="Permalink to &quot;Personal Notes&quot;">​</a></h3><p>Per-admin notepad persisted in the database. Accessible from the dashboard sidebar.</p><h3 id="rcon-console" tabindex="-1">RCON Console <a class="header-anchor" href="#rcon-console" aria-label="Permalink to &quot;RCON Console&quot;">​</a></h3><p>Send RCON commands directly from the dashboard. All commands are audit-logged.</p><h3 id="player-management" tabindex="-1">Player Management <a class="header-anchor" href="#player-management" aria-label="Permalink to &quot;Player Management&quot;">​</a></h3><ul><li>View all connected players with their groups, IPs, and GUIDs</li><li>Click a player for detailed info: aliases, penalties, XLR stats, gear loadout</li><li>Kick, ban, or change a player&#39;s group from the UI</li></ul><h3 id="xlrstats-leaderboards" tabindex="-1">XLRstats Leaderboards <a class="header-anchor" href="#xlrstats-leaderboards" aria-label="Permalink to &quot;XLRstats Leaderboards&quot;">​</a></h3><p>View top players by skill rating, with weapon and map statistics.</p><h3 id="audit-log" tabindex="-1">Audit Log <a class="header-anchor" href="#audit-log" aria-label="Permalink to &quot;Audit Log&quot;">​</a></h3><p>Complete history of all admin actions taken through the dashboard (RCON commands, kicks, bans, config changes).</p><h3 id="admin-users" tabindex="-1">Admin Users <a class="header-anchor" href="#admin-users" aria-label="Permalink to &quot;Admin Users&quot;">​</a></h3><p>Manage dashboard user accounts. Create, edit, and delete admin users. Change passwords and roles.</p><h3 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h3><p>View and edit the R3 configuration directly from the dashboard (admin-only). Changes are written to disk and applied on restart.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>The web dashboard consists of:</p><ul><li><strong>Backend:</strong> Axum HTTP server running inside the R3 process</li><li><strong>Frontend:</strong> SvelteKit 2 (Svelte 5) with Tailwind CSS, compiled to static files</li><li><strong>Real-time:</strong> WebSocket connection for live events (player joins, kills, chat, votes)</li><li><strong>Auth:</strong> JWT-based authentication with role-based access control</li></ul><p>The frontend is embedded into the Rust binary via <code>rust_embed</code> at compile time. No separate web server or Node.js runtime is required in production.</p><h2 id="security-notes" tabindex="-1">Security Notes <a class="header-anchor" href="#security-notes" aria-label="Permalink to &quot;Security Notes&quot;">​</a></h2><ul><li>All API endpoints require JWT authentication</li><li>Admin-only endpoints have additional role checks</li><li>RCON commands and config changes are recorded in the audit log</li><li>Set a fixed <code>jwt_secret</code> in production to persist sessions across restarts</li><li>Consider placing the dashboard behind a reverse proxy with TLS for production use</li></ul>`,38)])])}const b=e(r,[["render",o]]);export{u as __pageData,b as default};
